import boto3
import json
from typing import Dict, Any
from botocore.exceptions import ClientError

def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    # Initialize SNS client
    sns_client = boto3.client('sns')
    
    # Validate event data
    if not event.get('message') or not event.get('topic_arn'):
        return {
            'statusCode': 400,
            'body': json.dumps('Missing message or topic_arn in event')
        }
    
    message = event['message']
    topic_arn = event['topic_arn']
    
    # Validate topic ARN format (basic validation)
    if not topic_arn.startswith('arn:aws:sns:'):
        return {
            'statusCode': 400,
            'body': json.dumps('Invalid topic ARN format')
        }
    
    # Whitelist of allowed topics (implement based on your requirements)
    allowed_topics = [
        'arn:aws:sns:us-east-1:123456789012:notification-topic',
        'arn:aws:sns:us-east-1:123456789012:alert-topic'
    ]
    
    if topic_arn not in allowed_topics:
        return {
            'statusCode': 403,
            'body': json.dumps('Topic not authorized for publishing')
        }
    
    # Validate message content
    if not isinstance(message, (str, dict)):
        return {
            'statusCode': 400,
            'body': json.dumps('Invalid message format')
        }
    
    # Convert message to string if it's a dict
    if isinstance(message, dict):
        message = json.dumps(message)
    
    try:
        # Publish message to SNS topic
        response = sns_client.publish(
            TopicArn=topic_arn,
            Message=message,
            Subject=event.get('subject', 'Notification')
        )
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Message published successfully',
                'message_id': response['MessageId']
            })
        }
        
    except ClientError as e:
        error_code = e.response['Error']['Code']
        error_message = e.response['Error']['Message']
        
        return {
            'statusCode': 500,
            'body': json.dumps({
                'error': f'Failed to publish message: {error_message}',
                'error_code': error_code
            })
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({
                'error': f'Unexpected error: {str(e)}'
            })
        }